cd /tmp/sv-5ec32e7b87f04131a2b7174e3fd1a44b/advanced-multi-complexity && dotnet package list --format json 2>/dev/null | python3 -c "import sys,json; json.dump(json.load(sys.stdin), open('after-cpm-packages.json','w'), indent=2)" && echo "Saved" && python3 -c "
import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            key = f\"{name} ({fw['framework']})\"
            for pkg in fw['topLevelPackages']:
                result[(key, pkg['id'])] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

changes = []
unchanged = []

all_keys = sorted(set(list(b.keys()) + list(a.keys())))
for key in all_keys:
    proj, pkg = key
    bv = b.get(key)
    av = a.get(key)
    if bv and av and bv == av:
        unchanged.append((proj, pkg, av))
    elif bv and av and bv != av:
        changes.append((proj, pkg, bv, av, 'Aligned to highest version'))
    elif bv and not av:
        changes.append((proj, pkg, bv, '-', 'Removed'))
    elif not bv and av:
        changes.append((proj, pkg, '-', av, 'Added'))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'  {c[0]:30} {c[1]:45} {c[2]:>10} -> {c[3]:>10}  ({c[4]})')
else:
    print('  None')

print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'  {u[0]:30} {u[1]:45} {u[2]:>10}')
"

